mapper.select:
SELECT
  prc.id_ as id_,
  prc.proc_def_id_ as def_id_,
  def.key_ as key_,
  var.name_ as name_,
  var.var_type_ as type_
FROM ${prefix}ACT_HI_VARINST as var
JOIN ${prefix}ACT_HI_PROCINST as prc ON var.proc_inst_id_ = prc.id_
LEFT JOIN ${prefix}ACT_RE_PROCDEF as def ON prc.proc_def_id_ = def.id_

  LEFT JOIN ${prefix}ACT_RE_DEPLOYMENT as dep ON def.deployment_id_ = dep.id_



    AND def.key_ = #{definitionKey}


    #{type}


    AND prc.start_time_ >= #{startedAfter}


    AND def.deployment_id_ IN (
      SELECT id_ FROM ${prefix}ACT_RE_DEPLOYMENT
      ORDER BY deploy_time_ DESC
      LIMIT #{latestDeployments}
    )


GROUP BY prc.id_, prc.proc_def_id_, def.key_, var.name_, var.var_type_

SELECT proc_def_count.def_id_, proc_def_count.key_, MAX(proc_def_count.var_count_) as max_var_count FROM ( SELECT prc.id_, prc.proc_def_id_ as def_id_, COUNT(*) as var_count_, def.key_ FROM ${prefix}ACT_HI_VARINST as var JOIN ${prefix}ACT_HI_PROCINST as prc ON var.proc_inst_id_ = prc.id_ LEFT JOIN ${prefix}ACT_RE_PROCDEF as def ON prc.proc_def_id_ = def.id_
LEFT JOIN ${prefix}ACT_RE_DEPLOYMENT as dep ON def.deployment_id_ = dep.id_
AND def.key_ = #{definitionKey}
AND prc.start_time_ >= #{startedAfter}
AND def.deployment_id_ IN ( SELECT id_ FROM ${prefix}ACT_RE_DEPLOYMENT ORDER BY deploy_time_ DESC LIMIT #{latestDeployments} )
GROUP BY prc.id_, prc.proc_def_id_, def.key_ ) as proc_def_count GROUP BY def_id_, key_

SELECT
  var.id_ as id_,
  var.scope_id_ as scope_id_,
  var.scope_type_ as scope_type_,
  case_inst.case_def_id_ as scope_def_id_,
  def.key_ as scope_def_key_,
  var.name_ as name_,
  var.var_type_ as var_type_
FROM ${prefix}ACT_HI_VARINST as var
JOIN ${prefix}ACT_CMMN_HI_CASE_INST as case_inst ON var.scope_id_ = case_inst.id_
JOIN ${prefix}ACT_CMMN_CASEDEF as def ON case_inst.case_def_id_ = def.id_

  LEFT JOIN ${prefix}ACT_CMMN_DEPLOYMENT as dep ON def.deployment_id_ = dep.id_



    AND def.key_ = #{caseDefinitionKey}


    #{type}


    AND case_inst.start_time_ >= #{startedAfter}


    AND def.deployment_id_ IN (
      SELECT id_ FROM ${prefix}ACT_CMMN_DEPLOYMENT
      ORDER BY deploy_time_ DESC
      LIMIT #{latestDeployments}
    )


GROUP BY var.id_, var.scope_id_, var.scope_type_, case_inst.case_def_id_, def.key_, var.name_, var.var_type_
ORDER BY var.create_time_ DESC
